// Check dry-run mode. Set UPIS_DRY_RUN=true in Railway env to simulate without writing.
const dryRun = $env.UPIS_DRY_RUN === 'true';
return [{ json: { dry_run: dryRun, started_at: new Date().toISOString() } }];

// Calculate annual depreciation per item
const items = $input.all().map(item => {
  const data = item.json;
  const acquisitionCost = parseFloat(data.acquisition_cost ?? '0');
  const depreciationRate = parseFloat(data.depreciation_rate ?? '0');
  const prevAccum = parseFloat(data.accumulated_depreciation ?? '0');

  if (acquisitionCost <= 0 || depreciationRate <= 0) {
    return { json: { ...data, skipped: true, skip_reason: acquisitionCost <= 0 ? 'no_acquisition_cost' : 'zero_rate', annual_depreciation: 0, new_accumulated: prevAccum } };
  }

  const annualDepr = acquisitionCost * (depreciationRate / 100);
  const newAccum   = prevAccum + annualDepr;
  const netBookValue = Math.max(0, acquisitionCost - newAccum);

  return { json: {
    item_id: data.item_id,
    item_name: data.item_name,
    acquisition_cost: acquisitionCost,
    depreciation_rate: depreciationRate,
    annual_depreciation: parseFloat(annualDepr.toFixed(4)),
    prev_accumulated: prevAccum,
    new_accumulated: parseFloat(newAccum.toFixed(4)),
    net_book_value: parseFloat(netBookValue.toFixed(4)),
    skipped: false,
    journal: {
      journal_type: 'UPIS_DEPRECIATION',
      description:  `Annual UPIS depreciation — ${data.item_name}`,
      entries: [
        { account_code: '5310', type: 'Debit',  amount: parseFloat(annualDepr.toFixed(4)) },
        { account_code: '1990', type: 'Credit', amount: parseFloat(annualDepr.toFixed(4)) },
      ]
    }
  } };
});
return items;
